  const SVG_NS = 'http://www.w3.org/2000/svg';

  function renderBlueprintIcons(root = document) {
    const nodes = [];
    if (root?.matches?.('[data-bp-icon]')) nodes.push(root);
    root?.querySelectorAll?.('[data-bp-icon]')?.forEach((node) => nodes.push(node));
    for (const node of nodes) {
      if (node.dataset.bpIconRendered === 'true') continue;
      const definition = ICONS[node.dataset.bpIcon];
      if (!definition) {
        node.dataset.bpIconMissing = 'true';
        continue;
      }
      const svg = document.createElementNS(SVG_NS, 'svg');
      svg.setAttribute('viewBox', '0 0 16 16');
      svg.setAttribute('width', '16');
      svg.setAttribute('height', '16');
      svg.setAttribute('fill', 'currentColor');
      svg.setAttribute('focusable', 'false');
      svg.setAttribute('aria-hidden', 'true');
      svg.classList.add('bp-icon');
      svg.dataset.iconName = node.dataset.bpIcon;
      for (const pathData of definition.paths) {
        const pathNode = document.createElementNS(SVG_NS, 'path');
        pathNode.setAttribute('d', pathData);
        svg.append(pathNode);
      }
      node.replaceChildren(svg);
      node.dataset.bpIconRendered = 'true';
    }
    return nodes.length;
  }

